import{z as e}from"zod";export const GroupChatOrderSchema=e.enum(["fixed","round-robin","random"]),GroupChatConfigSchema=e.object({memberIds:e.array(e.string().min(1)).min(1),order:GroupChatOrderSchema.default("fixed"),turnInterval:e.number().int().min(1).max(10).default(1),scenario:e.string().default("")}),GroupChatMessageSchema=e.object({memberId:e.string(),memberName:e.string(),role:e.enum(["character","user"]),content:e.string(),timestamp:e.number().int()}),GroupChatSessionSchema=e.object({id:e.string(),config:GroupChatConfigSchema,memberNames:e.record(e.string(),e.string()),messages:e.array(GroupChatMessageSchema).default([]),currentTurnIndex:e.number().int().min(0).default(0),currentTurnCount:e.number().int().min(0).default(0),turnCount:e.number().int().min(0).default(0),lastSpeakerId:e.string().optional()});
